Here are the public test cases for feature2_import_aggregation:
{
  "description": "Aggregate the set of import directives required by a generated gallery from a list of source objects. The result always begins with two fixed framework imports, then includes each object's own import path (de-duplicated, first-seen order preserved). If any object is a widget that declares at least one provider-style dependency, an extra provider package import is appended. Output is one `import '...';` line per path.",
  "cases": [
    {
      "input": {
        "target": "imports",
        "objects": []
      },
      "expected_output": "import 'package:flutter/foundation.dart';\nimport 'package:flutter/material.dart';\n"
    },
    {
      "input": {
        "target": "imports",
        "objects": [
          {
            "import": "package:my_app/theme.dart"
          }
        ]
      },
      "expected_output": "import 'package:flutter/foundation.dart';\nimport 'package:flutter/material.dart';\nimport 'package:my_app/theme.dart';\n"
    }
  ]
}

Here are the public test cases for feature6_json_fragment_merge:
{
  "description": "Normalize a concatenation of independently-emitted JSON array fragments into a single array. When two array fragments are written back-to-back, the boundary where one array closes and the next opens (a closing bracket on its own line followed by a blank-line gap and a fresh opening bracket) is collapsed so the two element lists become one combined list. A single fragment with no such boundary is returned unchanged.",
  "cases": [
    {
      "input": {
        "target": "fix_json",
        "json": "[
  {
    "name": "TestWidget",
  }
]"
      },
      "expected_output": "[
  {
    "name": "TestWidget",
  }
]"
    },
    {
      "input": {
        "target": "fix_json",
        "json": "[
  {
    "name": "TestWidget",
  }
]

[
  {
    "name": "TestWidget",
  }
]"
      },
      "expected_output": "[
  {
    "name": "TestWidget",
  },
  {
    "name": "TestWidget",
  }
]"
    }
  ]
}

